#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,V=1e9+10;

struct Node{
    int sum,lc,rc;
}t[N*35];

int n,a[N],m,tot,rt[N];

void modify(int p,int q,int l,int r,int x){
    if(l==r){
        t[p].sum=t[q].sum+l;
        return;
    }
    int mid=l+r>>1;
    t[p].lc=t[q].lc;
    t[p].rc=t[q].rc;
    if(x<=mid){
        t[p].lc=++tot;
        modify(t[p].lc,t[q].lc,l,mid,x);
    }else{
        t[p].rc=++tot;
        modify(t[p].rc,t[q].rc,mid+1,r,x);
    }
    t[p].sum=t[t[p].lc].sum+t[t[p].rc].sum;
}

int query(int p,int q,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[p].sum-t[q].sum;
    int mid=l+r>>1;
    if(y<=mid)
        return query(t[p].lc,t[q].lc,l,mid,x,y);
    if(x>mid)
        return query(t[p].rc,t[q].rc,mid+1,r,x,y);
    return query(t[p].lc,t[q].lc,l,mid,x,y)+query(t[p].rc,t[q].rc,mid+1,r,x,y);
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++){
        rt[i]=++tot;
        modify(rt[i],rt[i-1],1,V,a[i]);
    }
    scanf("%d",&m);
    while(m--){
        int l,r;
        scanf("%d%d",&l,&r);
        int ans=1,lst;
        while(1){
            lst=ans;
            ans=max(ans,query(rt[r],rt[l-1],1,V,1,ans)+1);
            if(ans==lst)
                break;
        }
        printf("%d\n",ans);
    }
    return 0;
}
